python - <<'PY'
import json
from datetime import datetime, timedelta, date

src='day08/user_activity_raw.json'
with open(src) as f:
    data=json.load(f)

# reference "today" per user instruction/context
ref=date(2026,3,25)  # Wednesday

weekday_map={
    'monday':0,'tuesday':1,'wednesday':2,'thursday':3,'friday':4,'saturday':5,'sunday':6
}

def parse_last_login(s:str):
    s=s.strip().lower()
    if s=='today':
        return ref
    if s=='yesterday':
        return ref - timedelta(days=1)
    if s.endswith('day ago') or s.endswith('days ago'):
        n=int(s.split()[0])
        return ref - timedelta(days=n)
    if s.endswith('weeks ago') or s.endswith('week ago'):
        n=int(s.split()[0])
        return ref - timedelta(days=7*n)
    if s.startswith('last '):
        wd=s.split('last ',1)[1].strip()
        wd_num=weekday_map[wd]
        # go back to the most recent occurrence of that weekday before ref (not including ref)
        delta=(ref.weekday()-wd_num) % 7
        if delta==0:
            delta=7
        return ref - timedelta(days=delta)
    raise ValueError(f'Unrecognized last_login format: {s}')

last7_start=ref - timedelta(days=6)  # inclusive window: ref-6..ref

logins=[]
active=0
sessions_total=0

for u in data:
    login_date=parse_last_login(u['last_login'])
    logins.append({
        'user_id': u['user_id'],
        'last_login_raw': u['last_login'],
        'last_login_date': login_date.isoformat(),
        'session_count': u['session_count'],
        'active_days': u['active_days'],
        'is_active_last_7_days': login_date >= last7_start
    })
    if login_date >= last7_start:
        active += 1
    sessions_total += u['session_count']

total_users=len(data)
avg_sessions=round(sessions_total/total_users, 2) if total_users else 0.0

out={
    'generated_at': datetime.now().astimezone().isoformat(),
    'source_file': src,
    'reference_date': ref.isoformat(),
    'active_window_days': 7,
    'active_window_start': last7_start.isoformat(),
    'summary': {
        'total_users': total_users,
        'active_users': active,
        'avg_sessions': avg_sessions
    },
    'users': logins
}

out_path='day08/20260325_user_activity_analysis.json'
with open(out_path,'w') as f:
    json.dump(out,f,indent=2)

print('wrote', out_path)
print('summary', out['summary'])
PY
